It fails beacuse /dev/fd/1 is no longer connected because it is closed
on redir.c:148.

This seems to work:

--- redir.c.orig	Tue Oct  3 23:13:14 2000
+++ redir.c	Sat Sep  1 16:14:30 2001
@@ -143,13 +143,9 @@
 					break;
 				}
 			}
-			if (!try) {
+			if (!try)
 				sv->renamed[fd] = i;
-				close(fd);
-			}
 			INTON;
-		} else {
-			close(fd);
 		}
 		if (fd == 0)
 			fd0_redirected++;
@@ -186,6 +182,7 @@
 			error("cannot open %s: %s", fname, errmsg(errno, E_OPEN));
 movefd:
 		if (f != fd) {
+			close(fd);
 			copyfd(f, fd);
 			close(f);
 		}

